async function renderProposeForm(canPropose) {
  const wrap = document.getElementById('gov-propose');
  if (!wrap) return;
  if (!canPropose) { wrap.innerHTML = ''; return; }
  if (wrap.dataset.rendered === '1') return;
  wrap.dataset.rendered = '1';
  wrap.innerHTML =
    '<details class="gov-propose-card">' +
      '<summary>Create a proposal</summary>' +
      '<div class="gov-propose-body">' +
        '<label class="ws-label">Title <span class="ws-meta" id="gov-title-count">0 / ' + GOV.TITLE_MAX + '</span></label>' +
        '<input type="text" id="gov-title" maxlength="' + GOV.TITLE_MAX + '" placeholder="Short headline (e.g. \'Reduce LP fee to 0.2%\')">' +
        '<label class="ws-label">Body <span class="ws-meta" id="gov-body-count">0 / ' + GOV.BODY_MAX + ' bytes</span></label>' +
        '<textarea id="gov-body" placeholder="Full proposal text. Goes on-chain as event data — markdown is welcome but rendered as plain text on the page."></textarea>' +
        '<div class="gov-propose-actions">' +
          '<button class="gov-cta" id="gov-propose-btn">Sign &amp; submit on-chain</button>' +
          '<span id="gov-propose-status" class="ws-meta"></span>' +
        '</div>' +
        '<div class="gov-propose-note">Proposing requires <b>≥1 AHWA staked</b> in the governance contract — same threshold as voting. Skin in the game for governance, applies equally to proposers and voters. (Multisig vetoes are exempt — identity-based, not stake-based.)</div>' +
      '</div>' +
    '</details>';
  const titleEl = document.getElementById('gov-title');
  const bodyEl  = document.getElementById('gov-body');
  const tCount  = document.getElementById('gov-title-count');
  const bCount  = document.getElementById('gov-body-count');
  titleEl.oninput = () => { tCount.textContent = titleEl.value.length + ' / ' + GOV.TITLE_MAX; };
  bodyEl.oninput  = () => {
    const bytes = new TextEncoder().encode(bodyEl.value).length;
    bCount.textContent = bytes + ' / ' + GOV.BODY_MAX + ' bytes';
    bCount.style.color = bytes > GOV.BODY_MAX ? 'var(--red)' : '';
  };
  document.getElementById('gov-propose-btn').onclick = async () => {
    const s = document.getElementById('gov-propose-status');
    try {
      s.style.color = '';
      await doPropose(titleEl.value.trim(), bodyEl.value, s);
    } catch (e) { s.style.color = 'var(--red)'; s.textContent = '✗ ' + e.message; }
  };
}

// ─── Proposal cards (state-driven) ────────────────────────────────

function renderCollapsedCard(p) {
  const card = document.createElement('div');
  card.className = 'proposal-card';

  const now = Math.floor(Date.now() / 1000);
  const closesAt = p.createdAt + 72 * 3600;
  const finalAt  = closesAt + 3600;
  let timeStatus, timeClass, timeHelp;
  if      (now < closesAt) { timeStatus = 'OPEN';     timeClass = 'open';     timeHelp = 'Voting is open — proposal is within its 72-hour window.'; }
  else if (now < finalAt)  { timeStatus = 'TALLYING'; timeClass = 'tallying'; timeHelp = 'Voting closed; finalizing tally (1-hour buffer for late events).'; }
  else                     { timeStatus = 'FINAL';    timeClass = 'rejected'; timeHelp = 'Voting window has closed.'; }

  const dateStr = new Date(p.createdAt * 1000).toUTCString().replace(' GMT', ' UTC');
  const yes = fmtAhwa(p.totalYesWeight);
  const no  = fmtAhwa(p.totalNoWeight);

  card.innerHTML =
    '<div class="ph-head">' +
      '<div class="ph-title">Proposal #' + p.id + '</div>' +
      '<span class="ph-status ' + timeClass + '" title="' + escapeHTML(timeHelp) + '">' + timeStatus + '</span>' +
    '</div>' +
    '<div class="ph-meta">' +
      'by <a href="https://bscscan.com/address/' + p.proposer + '" target="_blank"><code>' + shortAddr(p.proposer) + '</code></a>' +
      ' · created <code>' + dateStr + '</code>' +
      ' · <b>' + yes + '</b> yes / <b>' + no + '</b> no AHWA staked' +
      (now < closesAt ? ' · <span class="ph-countdown" data-closes="' + closesAt + '">' + fmtCountdown(closesAt - now) + ' left</span>' : '') +
    '</div>' +
    '<div class="ph-tally-wrap">' +
      '<button class="gov-cta sm ph-load-btn">Load proposal · text · vote</button>' +
    '</div>';

  card.querySelector('.ph-load-btn').onclick = async () => {
    const wrap = card.querySelector('.ph-tally-wrap');
    wrap.innerHTML = '<div class="ph-loading">Loading proposal text + tally…</div>';
    try {
      // Fetch ProposalSubmitted event for title/body. Targeted block range.
      const latestBlk = await currentBlock();
      const elapsed = Math.max(0, Math.floor(Date.now() / 1000) - p.createdAt);
      const estBlock = Math.max(0, latestBlk - Math.floor(elapsed * 1.33));
      const fromBlock = Math.max(0, estBlock - 5000);
      const toBlock   = Math.min(latestBlk, estBlock + 49000);
      const proposalLogs = await rpcGetLogs(GOV.RPC, {
        fromBlock: '0x' + fromBlock.toString(16),
        toBlock:   '0x' + toBlock.toString(16),
        address: GOV.CONTRACT,
        topics:  [GOV.TOPICS.ProposalSubmitted, '0x' + encodeUint(p.id)],
      });
      if (proposalLogs.length === 0) throw new Error('ProposalSubmitted event not found in estimated window — try refreshing.');
      const ev = parseProposalLog(proposalLogs[0]);
      p.title = ev.title;
      p.body  = ev.body;
      p.blockNumber = ev.blockNumber;
      p.txHash = ev.txHash;

      // Fetch vetoes for this proposal (small range, narrow filter).
      const closesAtBlock = p.blockNumber + Math.ceil(72 * 3600 * 1.33);
      const vetoToBlock = Math.min(latestBlk, closesAtBlock);
      const vetoLogs = await rpcGetLogs(GOV.RPC, {
        fromBlock: '0x' + p.blockNumber.toString(16),
        toBlock:   '0x' + vetoToBlock.toString(16),
        address: GOV.CONTRACT,
        topics:  [GOV.TOPICS.VetoSubmitted, null, '0x' + encodeUint(p.id)],
      });
      const vetoes = vetoLogs.map(parseVetoLog);

      // Refresh tally from state (in case it changed since initial load).
      const fresh = await readProposal(p.id);
      p.totalYesWeight = fresh.totalYesWeight;
      p.totalNoWeight  = fresh.totalNoWeight;

      await renderTallySection(card, p, vetoes);
    } catch (e) {
      wrap.innerHTML = '<div class="ph-error">' + escapeHTML(e.message) + '</div>';
    }
  };

  return card;
}

async function renderTallySection(card, p, vetoes) {
  const now = Math.floor(Date.now() / 1000);
  const closesAt = p.createdAt + 72 * 3600;
  const finalAt  = closesAt + 3600;
  const isOpen = now < closesAt;

  const yesAhwa = fmtAhwa(p.totalYesWeight);
  const noAhwa  = fmtAhwa(p.totalNoWeight);
  const total = p.totalYesWeight + p.totalNoWeight;
  const passes = p.totalYesWeight > p.totalNoWeight && total > 0n;
  const vetoFired = vetoes.length >= 4;

  let status, statusClass, statusHelp;
  if      (isOpen)         { status = 'OPEN';              statusClass = 'open';     statusHelp = 'Voting is open. Tally below is live.'; }
  else if (now < finalAt)  { status = 'TALLYING';          statusClass = 'tallying'; statusHelp = 'Voting closed; final tally is settling.'; }
  else if (vetoFired)      { status = 'VETOED · REJECTED'; statusClass = 'vetoed';   statusHelp = '4+ multisig signers vetoed. Proposal killed regardless of community tally.'; }
  else if (passes)         { status = 'PASSED';            statusClass = 'passed';   statusHelp = 'Yes weight > No weight. Proposal passed.'; }
  else                     { status = 'REJECTED';          statusClass = 'rejected'; statusHelp = 'Yes weight did not exceed No weight, or no votes cast.'; }

  // Update head's status.
  const statusEl = card.querySelector('.ph-status');
  if (statusEl) {
    statusEl.className = 'ph-status ' + statusClass;
    statusEl.title = statusHelp;
    statusEl.textContent = status;
  }
  card.querySelector('.ph-title').textContent = '#' + p.id + ' — ' + p.title;
  const meta = card.querySelector('.ph-meta');
  if (!meta.dataset.augmented) {
    meta.dataset.augmented = '1';
    meta.insertAdjacentHTML('beforeend',
      ' · <a href="https://bscscan.com/tx/' + p.txHash + '" target="_blank">tx</a>' +
      ' · block <code>' + p.blockNumber + '</code>'
    );
  }

  // Determine voter capabilities.
  const connected = await getConnectedAddress();
  let connStaked = 0n, isMultisigSigner = false, prevWeight = 0n, prevYes = false;
  if (connected) {
    try {
      const s = await readWalletStatus(connected);
      connStaked = s.staked;
      isMultisigSigner = s.isMultisigSigner;
      if (connStaked > 0n) {
        prevWeight = await readVoteWeight(p.id, connected);
        if (prevWeight > 0n) prevYes = await readVoteYes(p.id, connected);
      }
    } catch {}
  }

  const canVote = isOpen && connected && connStaked >= GOV.MIN_AHWA;
  const canVeto = isOpen && isMultisigSigner;
  const alreadyVetoed = isMultisigSigner && vetoes.some(v => v.signer === connected);

  let actionHtml = '';
  if (canVote || canVeto) {
    const yesBtn = prevWeight > 0n ? (prevYes ? '✓ Voted YES (' + fmtAhwa(prevWeight) + ')' : 'Change to YES') : 'Vote YES';
    const noBtn  = prevWeight > 0n ? (!prevYes ? '✓ Voted NO (' + fmtAhwa(prevWeight) + ')' : 'Change to NO') : 'Vote NO';
    actionHtml = '<div class="ph-actions">';
    if (canVote) {
      actionHtml +=
        '<button class="gov-cta vote-yes ' + (prevWeight > 0n && prevYes ? 'active' : '') + '" data-pid="' + p.id + '" data-yes="1">' + yesBtn + '</button>' +
        '<button class="gov-cta vote-no '  + (prevWeight > 0n && !prevYes ? 'active' : '') + '" data-pid="' + p.id + '" data-yes="0">' + noBtn + '</button>';
    }
    if (canVeto) {
      actionHtml += '<button class="gov-cta danger veto-btn" data-pid="' + p.id + '"' + (alreadyVetoed ? ' disabled' : '') + '>' + (alreadyVetoed ? '✓ You vetoed' : 'VETO (multisig)') + '</button>';
    }
    actionHtml += '</div>';
    if (canVote) {
      actionHtml += '<div class="gov-propose-note">Voting weight = your <b>' + fmtAhwa(connStaked) + ' AHWA</b> staked.</div>';
    }
  } else if (connected && !canVote && !canVeto && isOpen) {
    actionHtml = '<div class="gov-propose-note" style="color:var(--text-dim)">You need to stake AHWA in the governance contract to vote. Use the <b>Stake / Unstake AHWA</b> button at the top.</div>';
  }

  const wrap = card.querySelector('.ph-tally-wrap');
  wrap.innerHTML =
    '<details class="ph-body" open><summary>Proposal text</summary><pre>' + escapeHTML(p.body) + '</pre></details>' +
    '<div class="tally-grid">' +
      '<div class="tally-col" title="Total AHWA staked behind YES votes (live, on-chain).">' +
        '<div class="l">YES (AHWA)</div><div class="v">' + yesAhwa + '</div></div>' +
      '<div class="tally-col" title="Total AHWA staked behind NO votes (live, on-chain).">' +
        '<div class="l">NO (AHWA)</div><div class="v">' + noAhwa + '</div></div>' +
      '<div class="tally-col" title="Total AHWA staked across all votes on this proposal.">' +
        '<div class="l">TOTAL</div><div class="v">' + fmtAhwa(total) + '</div></div>' +
      '<div class="tally-col" title="Yes weight as percentage of total voted weight.">' +
        '<div class="l">YES %</div><div class="v">' + (total > 0n ? Number(p.totalYesWeight * 10000n / total) / 100 : 0).toFixed(1) + '%</div></div>' +
    '</div>' +
    '<div class="tally-bar">' +
      (total > 0n
        ? '<div class="yes-fill" style="width:' + (Number(p.totalYesWeight * 1000n / total) / 10).toFixed(1) + '%"></div>' +
          '<div class="no-fill"  style="width:' + (Number(p.totalNoWeight  * 1000n / total) / 10).toFixed(1) + '%"></div>'
        : '') +
    '</div>' +
    (vetoes.length
      ? '<div class="veto-row">VETO signatures: <b>' + vetoes.length + '</b> of 5 multisig owners' +
          (vetoFired ? ' <span class="veto-pill">VETO FIRED (≥4/5)</span>' : '') + '</div>'
      : '') +
    actionHtml;

  // Wire vote/veto buttons.
  wrap.querySelectorAll('.vote-yes, .vote-no').forEach(btn => {
    btn.onclick = () => doVote(p.id, btn.dataset.yes === '1', btn).catch(e => {
      btn.disabled = false; btn.textContent = '✗ ' + e.message.slice(0, 60);
    });
  });
  const vetoBtn = wrap.querySelector('.veto-btn');
  if (vetoBtn) vetoBtn.onclick = () => doVeto(p.id, vetoBtn).catch(e => {
    vetoBtn.disabled = false; vetoBtn.textContent = '✗ ' + e.message.slice(0, 60);
  });
}

function tallyAndRender(proposals) {
  const wrap = document.getElementById('gov-proposals');
  wrap.innerHTML = '';

  if (proposals.length === 0) {
    wrap.innerHTML = '<div class="gov-empty">No proposals yet. Connect your wallet, stake at least 1 AHWA, then create a proposal or vote on one.</div>';
    return;
  }

  proposals.sort((a, b) => b.id - a.id);
  for (const p of proposals) {
    wrap.appendChild(renderCollapsedCard(p));
  }
}

// ─── main ──────────────────────────────────────────────────────────

async function runGovernance() {
  await renderAuditPanel();
  await renderWalletStatus();

  if (!GOV.CONTRACT) GOV.CONTRACT = localStorage.getItem('GOV_CONTRACT') || '';
  const contract = await renderDeployPanel();
  if (!contract) {
    document.getElementById('gov-proposals').innerHTML = '<div class="gov-empty">Awaiting contract deploy.</div>';
    await renderProposeForm(false);
    return;
  }

  // Fast path + state-driven proposal list. No log scan on initial load.
  let proposalCount = 0;
  try { proposalCount = await readProposalCount(); }
  catch (e) {
    document.getElementById('gov-proposals').innerHTML =
      '<div class="gov-empty" style="color:var(--red)">RPC error reading proposalCount: ' + escapeHTML(e.message) +
      '<br><br>If this is a 429 rate-limit, wait a few minutes and refresh.</div>';
    return;
  }
  if (proposalCount === 0) {
    tallyAndRender([]);
    const c = await getConnectedAddress();
    await renderProposeForm(c !== null);
    return;
  }

  // Read each proposal's state. Throttled to 3 concurrent.
  const proposals = [];
  for (let id = 1; id <= proposalCount; id++) {
    try { proposals.push(await readProposal(id)); }
    catch (e) { console.warn('proposal', id, 'failed:', e.message); }
  }

  tallyAndRender(proposals);
  const connected = await getConnectedAddress();
  await renderProposeForm(connected !== null);

  // Single setInterval drives all countdowns.
  if (!window._govCountdownInterval) {
    window._govCountdownInterval = setInterval(() => {
      const now = Math.floor(Date.now() / 1000);
      document.querySelectorAll('.ph-countdown').forEach(el => {
        const closes = parseInt(el.dataset.closes, 10);
        el.textContent = fmtCountdown(closes - now) + ' left';
      });
    }, 1000);
  }
}

// Auto-run on page load. `defer` ensures DOM is parsed and the inline
// main script (which defines RPC, SAFE, etc.) has already executed.
if (window.ethereum) {
  window.ethereum.on?.('accountsChanged', () => renderWalletStatus().catch(console.warn));
  window.ethereum.on?.('chainChanged',    () => renderWalletStatus().catch(console.warn));
}
runGovernance().catch(e => console.error('governance failed:', e));
